"use client";

import { useEffect, type RefObject } from "react";
import { getFocusableElements } from "../utils/navigation-items.js";
import { useFocusRestore } from "./use-focus-restore.js";

export interface UseFocusTrapOptions {
  initialFocus?: RefObject<HTMLElement | null>;
  restoreFocus?: boolean;
  enabled?: boolean;
}

export function useFocusTrap(
  containerRef: RefObject<HTMLElement | null>,
  options: UseFocusTrapOptions = {},
): void {
  const { initialFocus, restoreFocus = true, enabled = true } = options;
  const { capture, restore } = useFocusRestore({
    enabled: restoreFocus,
    restoreOnUnmount: restoreFocus,
  });

  useEffect(() => {
    if (!enabled) return;

    const container = containerRef.current;
    if (!container) return;
    capture();

    if (initialFocus?.current) {
      initialFocus.current.focus();
    } else {
      const focusables = getFocusableElements(container);
      if (focusables[0]) {
        focusables[0].focus();
      } else {
        container.focus();
      }
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key !== "Tab") return;

      const focusableEls = getFocusableElements(container);
      if (focusableEls.length === 0) {
        e.preventDefault();
        container.focus();
        return;
      }

      const first = focusableEls[0];
      const last = focusableEls[focusableEls.length - 1];

      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last?.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first?.focus();
        }
      }
    };

    container.addEventListener("keydown", handleKeyDown);
    return () => {
      container.removeEventListener("keydown", handleKeyDown);
      if (restoreFocus) restore();
    };
  }, [capture, containerRef, enabled, initialFocus, restore, restoreFocus]);
}

"use client";

import { useCallback, useEffect, useLayoutEffect, useRef, useState } from "react";
import {
  getRestorableFocusTarget,
  restoreFocus,
  type RestoreFocusOptions,
} from "../utils/focus-restore.js";

export interface UseFocusRestoreOptions extends RestoreFocusOptions {
  enabled?: boolean;
  restoreOnUnmount?: boolean;
  fallback?: HTMLElement | null;
}

export interface UseFocusRestoreReturn {
  capture: () => HTMLElement | null;
  restore: () => boolean;
  target: HTMLElement | null;
}

interface FocusRestoreEntry {
  target: HTMLElement | null;
}

const focusRestoreStack: FocusRestoreEntry[] = [];

function removeEntry(entry: FocusRestoreEntry): void {
  const index = focusRestoreStack.lastIndexOf(entry);
  if (index >= 0) focusRestoreStack.splice(index, 1);
}

function resolveOptions(options: UseFocusRestoreOptions): Required<UseFocusRestoreOptions> {
  return {
    enabled: options.enabled ?? true,
    restoreOnUnmount: options.restoreOnUnmount ?? true,
    preventScroll: options.preventScroll ?? false,
    fallback: options.fallback ?? null,
  };
}

function releaseEntry(
  entry: FocusRestoreEntry,
  shouldRestore: boolean,
  options: Required<UseFocusRestoreOptions>,
): boolean {
  const isTopEntry = focusRestoreStack.at(-1) === entry;
  removeEntry(entry);

  if (!shouldRestore || !options.enabled || !isTopEntry) return false;

  return (
    restoreFocus(entry.target, { preventScroll: options.preventScroll }) ||
    restoreFocus(options.fallback, { preventScroll: options.preventScroll })
  );
}

export function useFocusRestore(
  options: UseFocusRestoreOptions = {},
): UseFocusRestoreReturn {
  const resolvedOptions = resolveOptions(options);
  const optionsRef = useRef(resolvedOptions);
  const entryRef = useRef<FocusRestoreEntry | null>(null);
  const [target, setTarget] = useState<HTMLElement | null>(null);

  useLayoutEffect(() => {
    optionsRef.current = resolvedOptions;
  });

  const capture = useCallback(() => {
    const resolvedOptions = optionsRef.current;
    if (!resolvedOptions.enabled) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const nextTarget = getRestorableFocusTarget() ?? resolvedOptions.fallback;
    const entry = entryRef.current ?? { target: null };

    removeEntry(entry);
    entry.target = nextTarget;
    entryRef.current = entry;
    focusRestoreStack.push(entry);
    setTarget(nextTarget);

    return nextTarget;
  }, []);

  const restore = useCallback(() => {
    const resolvedOptions = optionsRef.current;
    const entry = entryRef.current;

    if (!entry) {
      return resolvedOptions.enabled
        ? restoreFocus(resolvedOptions.fallback, { preventScroll: resolvedOptions.preventScroll })
        : false;
    }

    entryRef.current = null;
    const restored = releaseEntry(entry, true, resolvedOptions);
    setTarget(null);
    return restored;
  }, []);

  useEffect(() => {
    if (resolvedOptions.enabled) return;

    const entry = entryRef.current;
    if (!entry) return;

    entryRef.current = null;
    removeEntry(entry);
    setTarget(null);
  }, [resolvedOptions.enabled]);

  useEffect(() => {
    return () => {
      const entry = entryRef.current;
      if (!entry) return;

      entryRef.current = null;
      releaseEntry(entry, optionsRef.current.restoreOnUnmount, optionsRef.current);
    };
  }, []);

  return { capture, restore, target };
}

export interface RestoreFocusOptions {
  preventScroll?: boolean;
}

function getDocument(): Document | null {
  return typeof document === "undefined" ? null : document;
}

function isHTMLElement(element: Element | null): element is HTMLElement {
  const View = element?.ownerDocument.defaultView;
  return Boolean(View && element instanceof View.HTMLElement);
}

export function getRestorableFocusTarget(ownerDocument?: Document): HTMLElement | null {
  const doc = ownerDocument ?? getDocument();
  if (!doc) return null;

  const activeElement = doc.activeElement;
  if (!isHTMLElement(activeElement)) return null;
  if (activeElement === doc.body || activeElement === doc.documentElement) return null;
  if (!activeElement.isConnected) return null;

  return activeElement;
}

export function restoreFocus(
  target: HTMLElement | null,
  options: RestoreFocusOptions = {},
): boolean {
  if (!target?.isConnected) return false;

  try {
    target.focus({ preventScroll: options.preventScroll });
  } catch {
    target.focus();
  }

  return target.ownerDocument.activeElement === target;
}

export const NAVIGATION_ITEM_ATTRIBUTE = "data-diffgazer-navigation-item";

const FOCUSABLE_SELECTOR = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "iframe",
  "object",
  "embed",
  "audio[controls]",
  "video[controls]",
  '[contenteditable]:not([contenteditable="false"])',
  '[tabindex]:not([tabindex="-1"]):not([disabled])',
].join(",");

export type NavigationItemType =
  | "radio"
  | "checkbox"
  | "option"
  | "menuitem"
  | "menuitemradio"
  | "button"
  | "tab";

export interface NavigationItemQuery {
  type: NavigationItemType;
  skipDisabled?: boolean;
  scopeToContainer?: boolean;
  ownerSelector?: string | null;
}

function disabledSelector(skipDisabled: boolean): string {
  return skipDisabled
    ? ':not([aria-disabled="true"]):not([data-disabled]):not(:disabled)'
    : "";
}

function findElements(container: HTMLElement, selector: string): HTMLElement[] {
  return Array.from(container.querySelectorAll<HTMLElement>(selector));
}

function queryFirstMatchingGroup(
  container: HTMLElement,
  selectors: string[],
  filter?: (element: HTMLElement) => boolean,
): HTMLElement[] {
  for (const selector of selectors) {
    const elements = filter
      ? findElements(container, selector).filter(filter)
      : findElements(container, selector);
    if (elements.length > 0) return elements;
  }
  return [];
}

function matchesNavigationDataContract(element: HTMLElement, type: NavigationItemType): boolean {
  const explicitType = element.getAttribute(NAVIGATION_ITEM_ATTRIBUTE);
  return explicitType === null || explicitType === "" || explicitType === "true" || explicitType === type;
}

function buildNavigationSelectors(
  type: NavigationItemType,
  skipDisabled: boolean,
): string[] {
  const disabled = disabledSelector(skipDisabled);
  const dataContractSelectors = [
    `[${NAVIGATION_ITEM_ATTRIBUTE}="${type}"][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}="true"][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}=""][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}][data-value]${disabled}`,
  ];
  const nativeRoleSelectors: Partial<Record<NavigationItemType, string[]>> = {
    button: [`button[data-value]${disabled}`],
    checkbox: [`input[type="checkbox"][data-value]${disabled}`],
    radio: [`input[type="radio"][data-value]${disabled}`],
  };

  return [
    dataContractSelectors.join(","),
    `[role="${type}"][data-value]${disabled}`,
    ...(nativeRoleSelectors[type] ?? []),
    `[role="${type}"]${disabled}`,
  ];
}

function ownerSelectorForType(type: NavigationItemType): string | null {
  switch (type) {
    case "radio":
      return '[role="radiogroup"]';
    case "checkbox":
      return '[role="group"]';
    case "option":
      return '[role="listbox"]';
    case "menuitem":
    case "menuitemradio":
      return '[role="menu"]';
    case "tab":
      return '[role="tablist"]';
    case "button":
      return null;
  }
}

function isOwnedByContainer(
  element: HTMLElement,
  container: HTMLElement,
  query: NavigationItemQuery,
) {
  if (query.scopeToContainer === false) return true;

  if (query.ownerSelector !== undefined) {
    if (query.ownerSelector === null) return true;
    const owner = element.closest(query.ownerSelector);
    return owner === null || owner === container;
  }

  const ownerSelector = ownerSelectorForType(query.type);
  if (!ownerSelector) return true;

  const owner = element.closest(ownerSelector);
  return owner === null || owner === container;
}

export function getNavigationItems(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): HTMLElement[] {
  if (!container) return [];

  return queryFirstMatchingGroup(
    container,
    buildNavigationSelectors(query.type, query.skipDisabled ?? true),
    (element) => matchesNavigationDataContract(element, query.type)
      && isOwnedByContainer(element, container, query),
  );
}

export function findNavigationItemByValue(
  container: HTMLElement | null,
  query: NavigationItemQuery & { value: string },
): HTMLElement | null {
  return getNavigationItems(container, query).find((element) => element.dataset.value === query.value) ?? null;
}

export function getNavigationItemProps(
  type: NavigationItemType,
  value: string,
): {
  "data-diffgazer-navigation-item": NavigationItemType;
  "data-value": string;
} {
  return {
    [NAVIGATION_ITEM_ATTRIBUTE]: type,
    "data-value": value,
  };
}

export function containsActiveElement(element: HTMLElement): boolean {
  const activeElement = element.ownerDocument.activeElement;
  const View = element.ownerDocument.defaultView;
  return Boolean(View && activeElement instanceof View.HTMLElement && element.contains(activeElement));
}

export function getFocusedNavigationValue(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): string | null {
  const focusedItem = getNavigationItems(container, query).find(containsActiveElement);
  return focusedItem?.dataset.value ?? null;
}

export function focusNavigationItem(
  container: HTMLElement | null,
  query: NavigationItemQuery & {
    value: string;
    fallback?: "first" | "last" | "none";
    preventScroll?: boolean;
  },
): string | null {
  const items = getNavigationItems(container, query);
  const target =
    items.find((element) => element.dataset.value === query.value) ??
    (query.fallback === "first" ? items[0] : undefined) ??
    (query.fallback === "last" ? items.at(-1) : undefined) ??
    null;

  if (!target || target.dataset.value === undefined) return null;

  target.focus({ preventScroll: query.preventScroll });
  return target.dataset.value;
}

export function getFocusableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR));
}
